# https://leetcode.com/problems/lexicographically-smallest-generated-string

def generateString(str1: str, str2:str) -> str:
    n, m = len(str1), len(str2)
    filled = [False] *  (n + m - 1)
    word = ['a'] * (n + m - 1)

    for i in range(n):
        if str1[i] == 'T':
            for j, c in enumerate(str2, i):
                if filled[j] and word[j] != c:
                    return ""
                word[j] = c
                filled[j] = True

    for i in range(n):
        ch = str1[i]
        if ch == 'F':
            if any(str2[j - i] != word[j] for j in range(i, i + m)):
                continue

            for j in range(i + m -1, i - 1, -1):
                if not filled[j]:
                    word[j] = 'b'
                    break
            else:
                return ""
    return "".join(word)



str1 = 'TFTF'
str2 = 'ab'

print(generateString(str1, str2))

str1 = ""
str2 = "bab"

print(generateString(str1, str2))